		_, _ = fmt.Fprintf(runtime.Output,
			"repaired project git config before execute-bead: %s (%s)\n",
			strings.Join(gitRepair.RepairedTypes, ", "),
			strings.Join(gitRepair.Commands, "; "),
		)
	}

